  async getRSource({ function_name, package: pkg }) {
    try {
      // Handle package::function and package:::function syntax
      let actualFunction = function_name;
      let actualPackage = pkg;
      let exportedOnly = true;

      if (function_name.includes(':::')) {
        const parts = function_name.split(':::');
        actualPackage = parts[0];
        actualFunction = parts[1];
        exportedOnly = false;
      } else if (function_name.includes('::')) {
        const parts = function_name.split('::');
        actualPackage = parts[0];
        actualFunction = parts[1];
      }

      // Remove backticks if present
      actualFunction = actualFunction.replace(/^`|`$/g, '');
      if (actualPackage) {
        actualPackage = actualPackage.replace(/^`|`$/g, '');
      }

      // Build the R script to get function source code
      // Note: We're not interpolating user input directly anymore
      const sourceScript = `
        tryCatch({
          func_name <- Sys.getenv("R_FUNC_NAME")
          pkg_name <- Sys.getenv("R_PKG_NAME")
          exported_only <- Sys.getenv("R_EXPORTED_ONLY") == "true"

          if (pkg_name != "") {
            # Check if package is installed
            if (!requireNamespace(pkg_name, quietly = TRUE)) {
              stop(paste0("Package '", pkg_name, "' is not installed. You may need to run: install.packages('", pkg_name, "')"))
            }

            # Get function from package namespace
            if (exported_only) {
              # Use :: which checks if function is exported
              func <- tryCatch(
                getFromNamespace(func_name, pkg_name),
                error = function(e) {
                  stop(paste0("Function '", func_name, "' not found in package '", pkg_name, "'. It may be internal (use ::: to access internal functions)."))
                }
              )
            } else {
              # Use ::: which can access internal functions
              ns <- asNamespace(pkg_name)
              if (!exists(func_name, envir = ns, mode = "function")) {
                stop(paste0("Function '", func_name, "' not found in package '", pkg_name, "'"))
              }
              func <- get(func_name, envir = ns, mode = "function")
            }
          } else {
            # Get function from global environment or search path
            if (!exists(func_name, mode = "function")) {
              stop(paste0("Function '", func_name, "' not found"))
            }
            func <- get(func_name, mode = "function")
          }

          # Check if it's a primitive function
          if (is.primitive(func)) {
            cat("This is a primitive function implemented in C code.\\n")
            cat("Primitive functions don't have R source code available.\\n")
            cat("Function: ", func_name, "\\n")
          } else {
            # Get the source code using capture.output (no temp files needed)
            source_code <- capture.output(print(func))
            cat(paste(source_code, collapse = "\\n"))
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_FUNC_NAME: actualFunction,
        R_PKG_NAME: actualPackage || '',
        R_EXPORTED_ONLY: exportedOnly.toString()
      };

      // Execute R script asynchronously
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', sourceScript], {
        encoding: 'utf8',
        maxBuffer: 50 * 1024 * 1024, // 50MB buffer for very large functions
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      // Check if error has stderr (from R quit with status 1)
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;

      return {
        content: [
          {
            type: 'text',
            text: `Error getting R function source: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getFunctionArgs({ function_name, package: pkg }) {
    try {
      // Handle package::function syntax
      let actualFunction = function_name;
      let actualPackage = pkg;

      if (function_name.includes(':::')) {
        const parts = function_name.split(':::');
        actualPackage = parts[0];
        actualFunction = parts[1];
      } else if (function_name.includes('::')) {
        const parts = function_name.split('::');
        actualPackage = parts[0];
        actualFunction = parts[1];
      }

      // Remove backticks if present
      actualFunction = actualFunction.replace(/^`|`$/g, '');
      if (actualPackage) {
        actualPackage = actualPackage.replace(/^`|`$/g, '');
      }

      const argsScript = `
        tryCatch({
          func_name <- Sys.getenv("R_FUNC_NAME")
          pkg_name <- Sys.getenv("R_PKG_NAME")

          # Get the function
          if (pkg_name != "") {
            if (!requireNamespace(pkg_name, quietly = TRUE)) {
              stop(paste0("Package '", pkg_name, "' is not installed"))
            }
            func <- getFromNamespace(func_name, pkg_name)
          } else {
            if (!exists(func_name, mode = "function")) {
              stop(paste0("Function '", func_name, "' not found"))
            }
            func <- get(func_name, mode = "function")
          }

          # Check if it's a primitive function
          if (is.primitive(func)) {
            cat("Primitive function: arguments defined at C level\\n")
            # Try to get args from help if available
            args_text <- tryCatch({
              capture.output(args(func))
            }, error = function(e) NULL)
            if (!is.null(args_text)) {
              cat(paste(args_text, collapse = "\\n"))
            }
          } else {
            # Get formal arguments
            formal_args <- formals(func)

            if (length(formal_args) == 0) {
              cat("Function has no arguments\\n")
            } else {
              cat("Arguments:\\n")
              for (i in seq_along(formal_args)) {
                arg_name <- names(formal_args)[i]
                arg_value <- formal_args[[i]]

                # Format the default value
                if (is.symbol(arg_value) && deparse(arg_value) == "") {
                  # No default value
                  cat(sprintf("  %s\\n", arg_name))
                } else if (is.language(arg_value) || is.call(arg_value)) {
                  # Expression as default
                  cat(sprintf("  %s = %s\\n", arg_name, deparse(arg_value)))
                } else if (is.character(arg_value)) {
                  # Character default
                  cat(sprintf("  %s = \\"%s\\"\\n", arg_name, arg_value))
                } else {
                  # Other defaults
                  cat(sprintf("  %s = %s\\n", arg_name, deparse(arg_value)))
                }
              }

              # Also show the function signature
              cat("\\nFunction signature:\\n")
              cat(paste(capture.output(args(func)), collapse = "\\n"))
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_FUNC_NAME: actualFunction,
        R_PKG_NAME: actualPackage || ''
      };

      // Execute R script asynchronously
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', argsScript], {
        encoding: 'utf8',
        maxBuffer: 10 * 1024 * 1024,
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error getting function arguments: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async listPackageFunctions({ package: pkg, include_internal = false }) {
    try {
      const listScript = `
        tryCatch({
          pkg_name <- Sys.getenv("R_PKG_NAME")
          include_internal <- Sys.getenv("R_INCLUDE_INTERNAL") == "true"

          # Check if package is installed
          if (!requireNamespace(pkg_name, quietly = TRUE)) {
            stop(paste0("Package '", pkg_name, "' is not installed"))
          }

          # Get package namespace
          ns <- asNamespace(pkg_name)

          if (include_internal) {
            # Get all objects from namespace
            all_names <- ls(envir = ns, all.names = TRUE)

            # Filter to only functions
            funcs <- character()
            for (name in all_names) {
              obj <- get(name, envir = ns)
              if (is.function(obj)) {
                funcs <- c(funcs, name)
              }
            }

            # Sort and categorize
            exported <- getNamespaceExports(pkg_name)
            exported_funcs <- sort(funcs[funcs %in% exported])
            internal_funcs <- sort(funcs[!funcs %in% exported])

            cat("Package:", pkg_name, "\\n")
            cat("Total functions:", length(funcs), "\\n\\n")

            if (length(exported_funcs) > 0) {
              cat("Exported functions (", length(exported_funcs), "):\\n", sep = "")
              for (f in exported_funcs) {
                cat("  ", f, "\\n", sep = "")
              }
            }

            if (length(internal_funcs) > 0) {
              cat("\\nInternal functions (", length(internal_funcs), "):\\n", sep = "")
              for (f in internal_funcs) {
                cat("  ", f, " (internal)\\n", sep = "")
              }
            }
          } else {
            # Get only exported functions
            exported <- getNamespaceExports(pkg_name)

            # Filter to only functions
            funcs <- character()
            for (name in exported) {
              tryCatch({
                obj <- get(name, envir = ns)
                if (is.function(obj)) {
                  funcs <- c(funcs, name)
                }
              }, error = function(e) {})
            }

            funcs <- sort(funcs)

            cat("Package:", pkg_name, "\\n")
            cat("Exported functions:", length(funcs), "\\n\\n")

            if (length(funcs) > 0) {
              for (f in funcs) {
                cat("  ", f, "\\n", sep = "")
              }
            } else {
              cat("No exported functions found\\n")
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_PKG_NAME: pkg,
        R_INCLUDE_INTERNAL: include_internal.toString()
      };

      // Execute R script asynchronously
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', listScript], {
        encoding: 'utf8',
        maxBuffer: 10 * 1024 * 1024,
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error listing package functions: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getExamples({ function_name, package: pkg, run_examples = false }) {
    try {
      // Handle package::function syntax
      let actualFunction = function_name;
      let actualPackage = pkg;

      if (function_name.includes(':::') || function_name.includes('::')) {
        const parts = function_name.split(/:::?/);
        actualPackage = parts[0];
        actualFunction = parts[1];
      }

      // Remove backticks if present
      actualFunction = actualFunction.replace(/^`|`$/g, '');
      if (actualPackage) {
        actualPackage = actualPackage.replace(/^`|`$/g, '');
      }

      const examplesScript = `
        tryCatch({
          func_name <- Sys.getenv("R_FUNC_NAME")
          pkg_name <- Sys.getenv("R_PKG_NAME")
          run_examples <- Sys.getenv("R_RUN_EXAMPLES") == "true"

          # Get help file path
          help_path <- if (pkg_name != "") {
            tryCatch(
              help(topic = func_name, package = pkg_name),
              error = function(e) character(0)
            )
          } else {
            tryCatch(
              help(topic = func_name),
              error = function(e) character(0)
            )
          }

          if (length(help_path) == 0) {
            stop(paste0("No help found for function '", func_name, "'", 
                       if(pkg_name != "") paste0(" in package '", pkg_name, "'") else ""))
          }

          # Get the Rd file content
          rd_content <- utils:::.getHelpFile(help_path)

          # Extract examples section
          examples <- utils:::.Rd_get_metadata(rd_content, "examples")

          if (length(examples) == 0 || all(trimws(examples) == "")) {
            cat("No examples found for this function.\\n")
          } else {
            examples_text <- paste(examples, collapse = "\\n")

            if (run_examples) {
              cat("=== EXAMPLES CODE ===\\n")
              cat(examples_text)
              cat("\\n\\n=== RUNNING EXAMPLES ===\\n")

              # Create temporary file for examples
              temp_file <- tempfile(fileext = ".R")
              writeLines(examples_text, temp_file)

              # Run examples in a try-catch
              tryCatch({
                # Set up example environment
                example_env <- new.env(parent = globalenv())

                # Source the examples
                source(temp_file, local = example_env, echo = TRUE, 
                       print.eval = TRUE, verbose = FALSE)
              }, error = function(e) {
                cat("\\nError running examples: ", e$message, "\\n")
              }, warning = function(w) {
                cat("\\nWarning: ", w$message, "\\n")
              }, finally = {
                unlink(temp_file)
              })
            } else {
              cat("=== EXAMPLES CODE ===\\n")
              cat(examples_text)
              cat("\\n\\nNote: Use run_examples=true to execute these examples\\n")
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_FUNC_NAME: actualFunction,
        R_PKG_NAME: actualPackage || '',
        R_RUN_EXAMPLES: run_examples.toString()
      };

      // Execute R script asynchronously
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', examplesScript], {
        encoding: 'utf8',
        maxBuffer: 50 * 1024 * 1024, // 50MB for example output
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error getting examples: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getPackageInfo({ package: pkg, show_dependencies = true }) {
