        },
        {
          name: 'get_session_info',
          description: 'Get R session information including version, platform, and loaded packages',
          inputSchema: {
            type: 'object',
            properties: {},
          },
        },
        {
          name: 'get_vignettes',
          description: 'List or read package vignettes',
          inputSchema: {
            type: 'object',
            properties: {
