  async getRHelp({ topic, package: pkg, format = 'text' }) {
    try {
      const tempFile = path.join(os.tmpdir(), `rhelp_${Date.now()}.txt`);

      // Handle package::function syntax
      let actualTopic = topic;
      let actualPackage = pkg;

      if (topic.includes('::')) {
        const parts = topic.split('::');
        actualPackage = parts[0];
        actualTopic = parts[1];
      }

      let rCommand;
      if (format === 'html') {
        rCommand = actualPackage
          ? `help("${actualTopic}", package="${actualPackage}", help_type="html")`
          : `help("${actualTopic}", help_type="html")`;
      } else {
        rCommand = actualPackage
          ? `help("${actualTopic}", package="${actualPackage}", help_type="text")`
          : `help("${actualTopic}", help_type="text")`;
      }

      const fullCommand = format === 'text'
        ? `Rscript -e '${rCommand}' > "${tempFile}" 2>&1`
        : `Rscript -e 'help_file <- ${rCommand}; if(length(help_file) > 0) { browseURL(help_file, browser = function(url) writeLines(readLines(url), "${tempFile.replace(/\\/g, '\\\\')}")) } else { writeLines("No help found", "${tempFile.replace(/\\/g, '\\\\')}") }'`;

      execSync(fullCommand, { encoding: 'utf8' });

      const content = await fs.readFile(tempFile, 'utf8');
      await fs.unlink(tempFile).catch(() => {});

      if (!content || content.trim() === 'No help found' || content.includes('No documentation')) {
        return {
          content: [
            {
              type: 'text',
              text: `No help documentation found for topic "${actualTopic}"${actualPackage ? ` in package "${actualPackage}"` : ''}. Make sure the topic exists and the package is installed.`,
            },
          ],
        };
      }

      return {
        content: [
          {
            type: 'text',
            text: content,
          },
        ],
      };
    } catch (error) {
      return {
        content: [
          {
            type: 'text',
            text: `Error getting R help: ${error.message}`,
          },
        ],
        isError: true,
      };
    }
  }

  async searchRHelp({ keyword, package: pkg }) {
    try {
      const searchScript = `
        tryCatch({
          keyword <- Sys.getenv("R_KEYWORD")
          pkg_name <- Sys.getenv("R_PKG_NAME")

          # First try help.search
          if (pkg_name != "") {
            results <- help.search(keyword, package = pkg_name)
          } else {
            results <- help.search(keyword)
          }

          if (nrow(results$matches) > 0) {
            # Found documentation - return as before
            matches <- results$matches
            output <- character()
            for(i in 1:nrow(matches)) {
              output <- c(output, paste0(
                matches[i, "Package"], "::", matches[i, "Name"], 
                " - ", matches[i, "Title"]
              ))
            }
            cat("=== DOCUMENTED FUNCTIONS ===\\n")
            cat(paste(output, collapse="\\n"))
          } else {
            # No documentation found - check if function exists
            found_objects <- list()

            if (pkg_name != "") {
              # Check specific package
              if (requireNamespace(pkg_name, quietly = TRUE)) {
                ns <- asNamespace(pkg_name)

                # Check if object exists in namespace or is re-exported
                obj <- NULL
                exists_in_ns <- exists(keyword, envir = ns, inherits = FALSE)

                if (exists_in_ns) {
                  obj <- get(keyword, envir = ns, inherits = FALSE)
                } else if (keyword %in% getNamespaceExports(pkg_name)) {
                  # It's re-exported, try to get it from package environment
                  pkg_env <- as.environment(paste0("package:", pkg_name))
                  if (exists(keyword, envir = pkg_env, inherits = FALSE)) {
                    obj <- get(keyword, envir = pkg_env, inherits = FALSE)
                  }
                }

                if (!is.null(obj)) {

                  # Check if it's exported
                  is_exported <- keyword %in% getNamespaceExports(pkg_name)

                  # Check if it's a function
                  is_function <- is.function(obj)

                  # Check if it's an S3 generic
                  is_s3_generic <- FALSE
                  s3_methods <- character()

                  if (is_function) {
                    # Check for S3 generic
                    is_s3_generic <- tryCatch({
                      # UseMethod check
                      body_text <- deparse(body(obj))
                      any(grepl("UseMethod", body_text))
                    }, error = function(e) FALSE)

                    # Get S3 methods
                    if (is_s3_generic) {
                      all_methods <- tryCatch({
                        methods(keyword)
                      }, error = function(e) character())

                      # Filter to methods from this package
                      s3_methods <- character()
                      for (method in all_methods) {
                        method_name <- as.character(method)
                        if (exists(method_name, envir = ns, inherits = FALSE)) {
                          s3_methods <- c(s3_methods, method_name)
                        }
                      }
                    }
                  }

                  found_objects[[pkg_name]] <- list(
                    exists = TRUE,
                    exported = is_exported,
                    is_function = is_function,
                    is_s3_generic = is_s3_generic,
                    s3_methods = s3_methods
                  )
                }
              }
            } else {
              # Search all loaded packages
              search_packages <- loadedNamespaces()

              for (p in search_packages) {
                ns <- asNamespace(p)

                # Check if object exists in namespace or is re-exported
                obj <- NULL
                exists_in_ns <- exists(keyword, envir = ns, inherits = FALSE)

                if (exists_in_ns) {
                  obj <- get(keyword, envir = ns, inherits = FALSE)
                } else if (keyword %in% getNamespaceExports(p)) {
                  # It's re-exported, try to get it from package environment
                  tryCatch({
                    pkg_env <- as.environment(paste0("package:", p))
                    if (exists(keyword, envir = pkg_env, inherits = FALSE)) {
                      obj <- get(keyword, envir = pkg_env, inherits = FALSE)
                    }
                  }, error = function(e) NULL)
                }

                if (!is.null(obj)) {
                  is_exported <- keyword %in% getNamespaceExports(p)
                  is_function <- is.function(obj)

                  is_s3_generic <- FALSE
                  s3_methods <- character()

                  if (is_function) {
                    is_s3_generic <- tryCatch({
                      body_text <- deparse(body(obj))
                      any(grepl("UseMethod", body_text))
                    }, error = function(e) FALSE)

                    if (is_s3_generic) {
                      all_methods <- tryCatch({
                        methods(keyword)
                      }, error = function(e) character())

                      for (method in all_methods) {
                        method_name <- as.character(method)
                        if (exists(method_name, envir = ns, inherits = FALSE)) {
                          s3_methods <- c(s3_methods, method_name)
                        }
                      }
                    }
                  }

                  found_objects[[p]] <- list(
                    exists = TRUE,
                    exported = is_exported,
                    is_function = is_function,
                    is_s3_generic = is_s3_generic,
                    s3_methods = s3_methods
                  )
                }
              }
            }

            # Format output
            if (length(found_objects) > 0) {
              cat("=== UNDOCUMENTED OBJECTS ===\\n\\n")
              cat("No documentation found, but the following objects exist:\\n\\n")

              for (pkg in names(found_objects)) {
                info <- found_objects[[pkg]]

                cat(pkg, "::", keyword, sep = "")

                if (!info$exported) {
                  cat(" (internal)")
                }

                if (info$is_function) {
                  cat(" [function]")

                  if (info$is_s3_generic) {
                    cat(" [S3 generic]")

                    if (length(info$s3_methods) > 0) {
                      cat("\\n  S3 methods found:\\n")
                      for (method in info$s3_methods) {
                        cat("    - ", method, "\\n", sep = "")
                      }
                    }
                  }
                } else {
                  cat(" [non-function object]")
                }

                cat("\\n")
              }

              cat("\\nTip: Use get_r_source('", keyword, "'", 
                  if(pkg_name != "") paste0(", package='", pkg_name, "'"), 
                  ") to see the source code\\n", sep = "")
            } else {
              cat("No matches found")
            }
          }
        }, error = function(e) {
          cat("Error: ", e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        R_KEYWORD: keyword,
        R_PKG_NAME: pkg || ''
      };

      // Execute R script asynchronously with timeout
      const { stdout, stderr } = await execRScriptWithTimeout(searchScript, env, 30000);

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim() || 'No matches found',
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error searching R help: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async listRPackages({ include_base = false }) {
    try {
      const rCommand = include_base
        ? 'installed.packages()[, c("Package", "Version")]'
        : 'installed.packages()[!installed.packages()[, "Priority"] %in% c("base", "recommended"), c("Package", "Version")]';

      const listScript = `
        pkgs <- ${rCommand}
        if(nrow(pkgs) > 0) {
          output <- apply(pkgs, 1, function(x) paste0(x[1], " (", x[2], ")"))
          cat(paste(sort(output), collapse="\\n"))
        } else {
          cat("No packages found")
        }
      `;

      const result = execSync(`Rscript -e '${listScript}'`, { encoding: 'utf8' });

      return {
        content: [
          {
            type: 'text',
            text: result.trim() || 'No packages found',
          },
        ],
      };
    } catch (error) {
      return {
        content: [
          {
            type: 'text',
            text: `Error listing R packages: ${error.message}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getRSource({ function_name, package: pkg }) {
    try {
      // Handle package::function and package:::function syntax
      let actualFunction = function_name;
      let actualPackage = pkg;
      let exportedOnly = true;

      if (function_name.includes(':::')) {
        const parts = function_name.split(':::');
        actualPackage = parts[0];
        actualFunction = parts[1];
        exportedOnly = false;
      } else if (function_name.includes('::')) {
        const parts = function_name.split('::');
        actualPackage = parts[0];
        actualFunction = parts[1];
      }

      // Remove backticks if present
      actualFunction = actualFunction.replace(/^`|`$/g, '');
      if (actualPackage) {
        actualPackage = actualPackage.replace(/^`|`$/g, '');
      }

      // Build the R script to get function source code
      // Note: We're not interpolating user input directly anymore
      const sourceScript = `
        tryCatch({
          func_name <- Sys.getenv("R_FUNC_NAME")
          pkg_name <- Sys.getenv("R_PKG_NAME")
          exported_only <- Sys.getenv("R_EXPORTED_ONLY") == "true"

          if (pkg_name != "") {
            # Check if package is installed
            if (!requireNamespace(pkg_name, quietly = TRUE)) {
              stop(paste0("Package '", pkg_name, "' is not installed. You may need to run: install.packages('", pkg_name, "')"))
            }

            # Get function from package namespace
            if (exported_only) {
              # Use :: which checks if function is exported
              func <- tryCatch(
                getFromNamespace(func_name, pkg_name),
                error = function(e) {
                  stop(paste0("Function '", func_name, "' not found in package '", pkg_name, "'. It may be internal (use ::: to access internal functions)."))
                }
              )
            } else {
              # Use ::: which can access internal functions
              ns <- asNamespace(pkg_name)
              if (!exists(func_name, envir = ns, mode = "function")) {
                stop(paste0("Function '", func_name, "' not found in package '", pkg_name, "'"))
              }
              func <- get(func_name, envir = ns, mode = "function")
            }
          } else {
            # Get function from global environment or search path
            if (!exists(func_name, mode = "function")) {
              stop(paste0("Function '", func_name, "' not found"))
            }
            func <- get(func_name, mode = "function")
          }

          # Check if it's a primitive function
          if (is.primitive(func)) {
            cat("This is a primitive function implemented in C code.\\n")
            cat("Primitive functions don't have R source code available.\\n")
            cat("Function: ", func_name, "\\n")
          } else {
            # Get the source code using capture.output (no temp files needed)
            source_code <- capture.output(print(func))
            cat(paste(source_code, collapse = "\\n"))
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_FUNC_NAME: actualFunction,
        R_PKG_NAME: actualPackage || '',
        R_EXPORTED_ONLY: exportedOnly.toString()
      };

      // Execute R script asynchronously with timeout
      const { stdout, stderr } = await execRScriptWithTimeout(sourceScript, env, 30000);

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      // Check if error has stderr (from R quit with status 1)
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;

      return {
        content: [
          {
            type: 'text',
            text: `Error getting R function source: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getFunctionArgs({ function_name, package: pkg }) {
    try {
      // Handle package::function syntax
      let actualFunction = function_name;
      let actualPackage = pkg;

      if (function_name.includes(':::')) {
        const parts = function_name.split(':::');
        actualPackage = parts[0];
        actualFunction = parts[1];
      } else if (function_name.includes('::')) {
        const parts = function_name.split('::');
        actualPackage = parts[0];
        actualFunction = parts[1];
      }

      // Remove backticks if present
      actualFunction = actualFunction.replace(/^`|`$/g, '');
      if (actualPackage) {
        actualPackage = actualPackage.replace(/^`|`$/g, '');
      }

      const argsScript = `
        tryCatch({
          func_name <- Sys.getenv("R_FUNC_NAME")
          pkg_name <- Sys.getenv("R_PKG_NAME")

          # Get the function
          if (pkg_name != "") {
            if (!requireNamespace(pkg_name, quietly = TRUE)) {
              stop(paste0("Package '", pkg_name, "' is not installed"))
            }
            func <- getFromNamespace(func_name, pkg_name)
          } else {
            if (!exists(func_name, mode = "function")) {
              stop(paste0("Function '", func_name, "' not found"))
            }
            func <- get(func_name, mode = "function")
          }

          # Check if it's a primitive function
          if (is.primitive(func)) {
            cat("Primitive function: arguments defined at C level\\n")
            # Try to get args from help if available
            args_text <- tryCatch({
              capture.output(args(func))
            }, error = function(e) NULL)
            if (!is.null(args_text)) {
              cat(paste(args_text, collapse = "\\n"))
            }
          } else {
            # Get formal arguments
            formal_args <- formals(func)

            if (length(formal_args) == 0) {
              cat("Function has no arguments\\n")
            } else {
              cat("Arguments:\\n")
              for (i in seq_along(formal_args)) {
                arg_name <- names(formal_args)[i]
                arg_value <- formal_args[[i]]

                # Format the default value
                if (is.symbol(arg_value) && deparse(arg_value) == "") {
                  # No default value
                  cat(sprintf("  %s\\n", arg_name))
                } else if (is.language(arg_value) || is.call(arg_value)) {
                  # Expression as default
                  cat(sprintf("  %s = %s\\n", arg_name, deparse(arg_value)))
                } else if (is.character(arg_value)) {
                  # Character default
                  cat(sprintf("  %s = \\"%s\\"\\n", arg_name, arg_value))
                } else {
                  # Other defaults
                  cat(sprintf("  %s = %s\\n", arg_name, deparse(arg_value)))
                }
              }

              # Also show the function signature
              cat("\\nFunction signature:\\n")
              cat(paste(capture.output(args(func)), collapse = "\\n"))
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_FUNC_NAME: actualFunction,
        R_PKG_NAME: actualPackage || ''
      };

      // Execute R script asynchronously with timeout
      const { stdout, stderr } = await execRScriptWithTimeout(argsScript, env, 30000);

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error getting function arguments: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async listPackageFunctions({ package: pkg, include_internal = false }) {
    try {
      const listScript = `
        tryCatch({
          pkg_name <- Sys.getenv("R_PKG_NAME")
          include_internal <- Sys.getenv("R_INCLUDE_INTERNAL") == "true"

          # Check if package is installed
          if (!requireNamespace(pkg_name, quietly = TRUE)) {
            stop(paste0("Package '", pkg_name, "' is not installed"))
          }

          # Get package namespace
          ns <- asNamespace(pkg_name)

          if (include_internal) {
            # Get all objects from namespace
            all_names <- ls(envir = ns, all.names = TRUE)

            # Filter to only functions
            funcs <- character()
            for (name in all_names) {
              obj <- get(name, envir = ns)
              if (is.function(obj)) {
                funcs <- c(funcs, name)
              }
            }

            # Sort and categorize
            exported <- getNamespaceExports(pkg_name)
            exported_funcs <- sort(funcs[funcs %in% exported])
            internal_funcs <- sort(funcs[!funcs %in% exported])

            cat("Package:", pkg_name, "\\n")
            cat("Total functions:", length(funcs), "\\n\\n")

            if (length(exported_funcs) > 0) {
              cat("Exported functions (", length(exported_funcs), "):\\n", sep = "")
              for (f in exported_funcs) {
                cat("  ", f, "\\n", sep = "")
              }
            }

            if (length(internal_funcs) > 0) {
              cat("\\nInternal functions (", length(internal_funcs), "):\\n", sep = "")
              for (f in internal_funcs) {
                cat("  ", f, " (internal)\\n", sep = "")
              }
            }
          } else {
            # Get only exported functions
            exported <- getNamespaceExports(pkg_name)

            # Filter to only functions
            funcs <- character()
            for (name in exported) {
              tryCatch({
                obj <- get(name, envir = ns)
                if (is.function(obj)) {
                  funcs <- c(funcs, name)
                }
              }, error = function(e) {})
            }

            funcs <- sort(funcs)

            cat("Package:", pkg_name, "\\n")
            cat("Exported functions:", length(funcs), "\\n\\n")

            if (length(funcs) > 0) {
              for (f in funcs) {
                cat("  ", f, "\\n", sep = "")
              }
            } else {
              cat("No exported functions found\\n")
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_PKG_NAME: pkg,
        R_INCLUDE_INTERNAL: include_internal.toString()
      };

      // Execute R script asynchronously
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', listScript], {
        encoding: 'utf8',
        maxBuffer: 10 * 1024 * 1024,
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error listing package functions: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getExamples({ function_name, package: pkg, run_examples = false }) {
    try {
      // Handle package::function syntax
      let actualFunction = function_name;
      let actualPackage = pkg;

      if (function_name.includes(':::') || function_name.includes('::')) {
        const parts = function_name.split(/:::?/);
        actualPackage = parts[0];
        actualFunction = parts[1];
      }

      // Remove backticks if present
      actualFunction = actualFunction.replace(/^`|`$/g, '');
      if (actualPackage) {
        actualPackage = actualPackage.replace(/^`|`$/g, '');
      }

      const examplesScript = `
        tryCatch({
          func_name <- Sys.getenv("R_FUNC_NAME")
          pkg_name <- Sys.getenv("R_PKG_NAME")
          run_examples <- Sys.getenv("R_RUN_EXAMPLES") == "true"

          # Get help file path
          help_path <- if (pkg_name != "") {
            tryCatch(
              help(topic = func_name, package = pkg_name),
              error = function(e) character(0)
            )
          } else {
            tryCatch(
              help(topic = func_name),
              error = function(e) character(0)
            )
          }

          if (length(help_path) == 0) {
            stop(paste0("No help found for function '", func_name, "'", 
                       if(pkg_name != "") paste0(" in package '", pkg_name, "'") else ""))
          }

          # Get the Rd file content
          rd_content <- utils:::.getHelpFile(help_path)

          # Extract examples section
          examples <- utils:::.Rd_get_metadata(rd_content, "examples")

          if (length(examples) == 0 || all(trimws(examples) == "")) {
            cat("No examples found for this function.\\n")
          } else {
            examples_text <- paste(examples, collapse = "\\n")

            if (run_examples) {
              cat("=== EXAMPLES CODE ===\\n")
              cat(examples_text)
              cat("\\n\\n=== RUNNING EXAMPLES ===\\n")

              # Create temporary file for examples
              temp_file <- tempfile(fileext = ".R")
              writeLines(examples_text, temp_file)

              # Run examples in a try-catch
              tryCatch({
                # Set up example environment
                example_env <- new.env(parent = globalenv())

                # Source the examples
                source(temp_file, local = example_env, echo = TRUE, 
                       print.eval = TRUE, verbose = FALSE)
              }, error = function(e) {
                cat("\\nError running examples: ", e$message, "\\n")
              }, warning = function(w) {
                cat("\\nWarning: ", w$message, "\\n")
              }, finally = {
                unlink(temp_file)
              })
            } else {
              cat("=== EXAMPLES CODE ===\\n")
              cat(examples_text)
              cat("\\n\\nNote: Use run_examples=true to execute these examples\\n")
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_FUNC_NAME: actualFunction,
        R_PKG_NAME: actualPackage || '',
        R_RUN_EXAMPLES: run_examples.toString()
      };

      // Execute R script asynchronously
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', examplesScript], {
        encoding: 'utf8',
        maxBuffer: 50 * 1024 * 1024, // 50MB for example output
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error getting examples: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getPackageInfo({ package: pkg, show_dependencies = true }) {
    try {
      const infoScript = `
        tryCatch({
          pkg_name <- Sys.getenv("R_PKG_NAME")
          show_deps <- Sys.getenv("R_SHOW_DEPS") == "true"

          # Check if package is installed
          if (!requireNamespace(pkg_name, quietly = TRUE)) {
            stop(paste0("Package '", pkg_name, "' is not installed"))
