  async searchDatasets({ keyword, package: pkg, show_info = true }) {
    try {
      const searchScript = `
        tryCatch({
          keyword <- Sys.getenv("R_KEYWORD")
          pkg_name <- Sys.getenv("R_PKG_NAME")
          show_info <- Sys.getenv("R_SHOW_INFO") == "true"

          # Get list of datasets
          if (pkg_name != "") {
            # Check if package is installed
            if (!requireNamespace(pkg_name, quietly = TRUE)) {
              stop(paste0("Package '", pkg_name, "' is not installed"))
            }

            # Get datasets from specific package
            data_info <- tryCatch({
              data(package = pkg_name)$results
            }, error = function(e) {
              NULL
            })
          } else {
            # Get datasets from all packages
            data_info <- data()$results
          }

          if (is.null(data_info) || nrow(data_info) == 0) {
            cat("No datasets found", 
                if(pkg_name != "") paste0(" in package '", pkg_name, "'"), 
                "\\n", sep = "")
            quit(save = "no", status = 0)
          }

          # Filter by keyword if provided
          if (keyword != "") {
            # Search in Item (dataset name) and Title (description)
            matches <- grepl(keyword, data_info[, "Item"], ignore.case = TRUE) |
                      grepl(keyword, data_info[, "Title"], ignore.case = TRUE)
            data_info <- data_info[matches, , drop = FALSE]
          }

          if (nrow(data_info) == 0) {
            cat("No datasets found matching '", keyword, "'", 
                if(pkg_name != "") paste0(" in package '", pkg_name, "'"), 
                "\\n", sep = "")
            quit(save = "no", status = 0)
          }

          cat("Found ", nrow(data_info), " dataset(s)\\n\\n", sep = "")

          # Show results
          for (i in 1:nrow(data_info)) {
            pkg <- data_info[i, "Package"]
            item <- data_info[i, "Item"]
            title <- data_info[i, "Title"]

            cat("=== ", pkg, "::", item, " ===\\n", sep = "")
            cat("Description: ", title, "\\n", sep = "")

            if (show_info) {
              # Try to load and show structure
              tryCatch({
                # Load the dataset temporarily
                data(list = item, package = pkg, envir = environment())
                dataset <- get(item, envir = environment())

                # Show basic info
                if (is.data.frame(dataset)) {
                  cat("Type: data.frame\\n")
                  cat("Dimensions: ", nrow(dataset), " rows x ", ncol(dataset), " columns\\n", sep = "")
                  cat("\\nColumn names:\\n")
                  cols <- names(dataset)
                  for (j in seq_along(cols)) {
                    cat("  ", cols[j], " (", class(dataset[[j]])[1], ")\\n", sep = "")
                  }
                } else if (is.matrix(dataset)) {
                  cat("Type: matrix\\n")
                  cat("Dimensions: ", nrow(dataset), " x ", ncol(dataset), "\\n", sep = "")
                } else if (is.list(dataset)) {
                  cat("Type: list\\n")
                  cat("Length: ", length(dataset), "\\n", sep = "")
                  if (length(names(dataset)) > 0) {
                    cat("Elements: ", paste(names(dataset), collapse = ", "), "\\n", sep = "")
                  }
                } else {
                  cat("Type: ", class(dataset)[1], "\\n", sep = "")
                  if (is.vector(dataset)) {
                    cat("Length: ", length(dataset), "\\n", sep = "")
                  }
                }

                # Clean up
                rm(list = item, envir = environment())
              }, error = function(e) {
                cat("(Unable to load dataset for inspection)\\n")
              })
            }

            cat("\\n")
          }

        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_KEYWORD: keyword || '',
        R_PKG_NAME: pkg || '',
        R_SHOW_INFO: show_info.toString()
      };

      // Execute R script asynchronously
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', searchScript], {
        encoding: 'utf8',
        maxBuffer: 20 * 1024 * 1024,
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error searching datasets: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

