      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_PKG_NAME: pkg,
        R_SHOW_DEPS: show_dependencies.toString()
      };

      // Execute R script asynchronously with timeout
      const { stdout, stderr } = await execRScriptWithTimeout(infoScript, env, 30000);

