  async getVignettes({ package: pkg, vignette_name }) {
    try {
      const vignetteScript = `
        tryCatch({
          pkg_name <- Sys.getenv("R_PKG_NAME")
          vignette_name <- Sys.getenv("R_VIGNETTE_NAME")

          # Check if package is installed
          if (!requireNamespace(pkg_name, quietly = TRUE)) {
            stop(paste0("Package '", pkg_name, "' is not installed"))
          }

          if (vignette_name == "") {
            # List all vignettes
            vigs <- vignette(package = pkg_name)$results

            if (nrow(vigs) == 0) {
              cat("No vignettes found for package '", pkg_name, "'\\n", sep = "")
            } else {
              cat("=== VIGNETTES IN PACKAGE '", toupper(pkg_name), "' ===\\n\\n", sep = "")
              cat("Found ", nrow(vigs), " vignette(s):\\n\\n", sep = "")

              for (i in 1:nrow(vigs)) {
                cat(i, ". ", vigs[i, "Item"], "\\n", sep = "")
                cat("   Title: ", vigs[i, "Title"], "\\n", sep = "")
                cat("   PDF: ", vigs[i, "PDF"], "\\n\\n", sep = "")
              }

              cat("\\nTo read a specific vignette, provide the vignette name.\\n")
            }
          } else {
            # Try to get specific vignette content
            vigs <- vignette(package = pkg_name)$results
            vignette_items <- vigs[, "Item"]

            # Find matching vignette (case insensitive)
            match_idx <- which(tolower(vignette_items) == tolower(vignette_name))

            if (length(match_idx) == 0) {
              cat("Vignette '", vignette_name, "' not found in package '", pkg_name, "'\\n\\n", sep = "")
              cat("Available vignettes:\\n")
              for (item in vignette_items) {
                cat("  - ", item, "\\n", sep = "")
              }
            } else {
              # Get the vignette
              vig_name <- vignette_items[match_idx[1]]

              cat("=== VIGNETTE: ", vig_name, " ===\\n", sep = "")
              cat("Package: ", pkg_name, "\\n", sep = "")
              cat("Title: ", vigs[match_idx[1], "Title"], "\\n\\n", sep = "")

              # Try to read the R source file
              vig_info <- vignette(vig_name, package = pkg_name)

              if (length(vig_info$file) > 0) {
                # Read the source file
                source_file <- vig_info$file

                if (file.exists(source_file)) {
                  # Determine file type
                  if (grepl("\\\\.Rmd$", source_file, ignore.case = TRUE)) {
                    cat("Source format: R Markdown\\n\\n")
                  } else if (grepl("\\\\.Rnw$", source_file, ignore.case = TRUE)) {
                    cat("Source format: Sweave\\n\\n")
                  } else if (grepl("\\\\.R$", source_file, ignore.case = TRUE)) {
                    cat("Source format: R script\\n\\n")
                  }

                  cat("--- VIGNETTE CONTENT ---\\n\\n")
                  content <- readLines(source_file)
                  cat(paste(content, collapse = "\\n"))
                } else {
                  cat("Source file not found: ", source_file, "\\n", sep = "")
                  cat("\\nNote: You may need to use browseVignettes('", pkg_name, "') in an R session to view this vignette.\\n", sep = "")
                }
              } else {
                cat("Unable to locate vignette source file.\\n")
                cat("Note: You may need to use browseVignettes('", pkg_name, "') in an R session to view this vignette.\\n", sep = "")
              }
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_PKG_NAME: pkg,
        R_VIGNETTE_NAME: vignette_name || ''
      };

      // Execute R script asynchronously with timeout (50MB for vignette content)
      const { stdout, stderr } = await execRScriptWithTimeout(vignetteScript, env, 30000, 50);

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error getting vignettes: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async runPackageCheck({ pkgPath = '.', args = '', quiet = true }) {
    try {
      // Security: Validate arguments against whitelist
      const ALLOWED_ARGS = [
        '--as-cran',
        '--no-manual',
        '--no-vignettes', 
        '--no-build-vignettes',
        '--no-examples',
        '--no-tests',
        '--no-codoc',
        '--no-install',
        '--ignore-vignettes',
        '--timings'
      ];

      // Parse arguments properly handling quoted values
      let parsedArgs = [];
      if (args) {
        // Custom parsing to handle quoted values with spaces
        const argsList = [];
        let current = '';
        let inQuotes = false;
        let quoteChar = '';

        for (let i = 0; i < args.length; i++) {
          const char = args[i];
          const prevChar = i > 0 ? args[i-1] : '';

          if (!inQuotes && (char === '"' || char === "'") && prevChar === '=') {
            // Start of quoted value
            inQuotes = true;
            quoteChar = char;
          } else if (inQuotes && char === quoteChar) {
            // End of quoted value
            inQuotes = false;
            quoteChar = '';
          } else if (!inQuotes && char === ' ') {
            // Space outside quotes - end of argument
            if (current.trim()) {
              argsList.push(current.trim());
              current = '';
            }
          } else {
            // Regular character
            current += char;
          }
        }

        // Don't forget the last argument
        if (current.trim()) {
          argsList.push(current.trim());
        }

        // Validate each argument
        for (const arg of argsList) {
          const argName = arg.split('=')[0];

          if (!ALLOWED_ARGS.includes(argName)) {
            return {
              content: [
                {
                  type: 'text',
                  text: `Error: Disallowed argument '${argName}'\n\nAllowed arguments: ${ALLOWED_ARGS.join(', ')}`,
                },
              ],
              isError: true,
            };
          }
          parsedArgs.push(arg);
        }
      }

      // Security: Resolve path to prevent traversal
      const resolvedPath = path.resolve(pkgPath);

      // Get current working directory as base for relative paths
      const cwd = process.cwd();

      // For Claude Code context, we trust the user's file system access
      // but we'll validate the path exists and has a DESCRIPTION file

      const checkScript = `
        # Set options for rcmdcheck
        pkg_path <- Sys.getenv("R_PKG_PATH")
        check_args_json <- Sys.getenv("R_CHECK_ARGS_JSON")
        be_quiet <- Sys.getenv("R_QUIET") == "true"

        # First check if rcmdcheck is installed
        if (!requireNamespace("rcmdcheck", quietly = TRUE)) {
          cat("ERROR: rcmdcheck package is not installed\\n")
          cat("\\nTo install it, run:\\n")
          cat("install.packages('rcmdcheck')\\n")
          quit(save = "no", status = 1)
        }

        # Check if the path is a valid R package
        if (!file.exists(file.path(pkg_path, "DESCRIPTION"))) {
          cat("ERROR: No DESCRIPTION file found at ", pkg_path, "\\n")
          cat("\\nThe run_package_check function is designed to check R packages.\\n")
          cat("It requires a DESCRIPTION file that defines the package metadata.\\n")
          cat("\\nTo use this function:\\n")
          cat("1. Navigate to an R package directory (one with a DESCRIPTION file)\\n")
          cat("2. Or specify the path to an R package with the pkgPath parameter\\n")
          cat("\\nIf you're trying to create a new R package, you can use:\\n")
          cat("   usethis::create_package('my_package_name')\\n")
          cat("   or devtools::create('my_package_name')\\n")
          quit(save = "no", status = 1)
        }

        # Get package name
        desc <- tryCatch({
          read.dcf(file.path(pkg_path, "DESCRIPTION"), fields = "Package")
        }, error = function(e) {
          cat("ERROR: Could not read DESCRIPTION file: ", e$message, "\\n")
          quit(save = "no", status = 1)
        })

        if (is.null(desc) || !("Package" %in% colnames(desc)) || is.na(desc[1, "Package"])) {
          cat("ERROR: Could not read package name from DESCRIPTION file\\n")
          cat("Make sure the DESCRIPTION file has a valid 'Package:' field\\n")
          quit(save = "no", status = 1)
        }

        pkg_name <- desc[1, "Package"]

        cat("=== R CMD CHECK FOR PACKAGE: ", pkg_name, " ===\\n\\n", sep = "")
        cat("Running checks... This may take a few minutes.\\n\\n")

        # Parse arguments from JSON
        check_args <- if(check_args_json != "") {
          tryCatch({
            jsonlite::fromJSON(check_args_json)
          }, error = function(e) {
            cat("ERROR parsing arguments: ", e$message, "\\n")
            quit(save = "no", status = 1)
          })
        } else {
          character()
        }

        # Run the check
        check_result <- tryCatch({
          rcmdcheck::rcmdcheck(
            path = pkg_path,
            args = check_args,
            quiet = be_quiet,
            error_on = "never"
          )
        }, error = function(e) {
          cat("ERROR running check: ", e$message, "\\n")
          quit(save = "no", status = 1)
        })

        # Format results as a todo list
        cat("\\n=== CHECK RESULTS ===\\n\\n")

        # Summary
        n_errors <- length(check_result$errors)
        n_warnings <- length(check_result$warnings)
        n_notes <- length(check_result$notes)

        cat("Summary: ", n_errors, " errors | ", n_warnings, " warnings | ", n_notes, " notes\\n\\n", sep = "")

        # Create todo list
        cat("=== TODO LIST ===\\n\\n")

        todo_count <- 0

        # Errors (highest priority)
        if (n_errors > 0) {
          cat("## ERRORS (Must fix):\\n\\n")
          for (i in seq_along(check_result$errors)) {
            todo_count <- todo_count + 1
            error_text <- trimws(check_result$errors[i])
            # Try to extract the main error message
            lines <- strsplit(error_text, "\\n")[[1]]
            main_error <- lines[1]
            cat(todo_count, ". [ERROR] ", main_error, "\\n", sep = "")
            if (length(lines) > 1) {
              # Add some context
              for (j in 2:min(4, length(lines))) {
                if (nchar(trimws(lines[j])) > 0) {
                  cat("   ", trimws(lines[j]), "\\n", sep = "")
                }
              }
            }
            cat("\\n")
          }
        }

        # Warnings (medium priority)
        if (n_warnings > 0) {
          cat("## WARNINGS (Should fix):\\n\\n")
          for (i in seq_along(check_result$warnings)) {
            todo_count <- todo_count + 1
            warning_text <- trimws(check_result$warnings[i])
            lines <- strsplit(warning_text, "\\n")[[1]]
            main_warning <- lines[1]
            cat(todo_count, ". [WARNING] ", main_warning, "\\n", sep = "")
            if (length(lines) > 1) {
              for (j in 2:min(4, length(lines))) {
                if (nchar(trimws(lines[j])) > 0) {
                  cat("   ", trimws(lines[j]), "\\n", sep = "")
                }
              }
            }
            cat("\\n")
          }
        }

        # Notes (low priority)
        if (n_notes > 0) {
          cat("## NOTES (Consider fixing):\\n\\n")
          for (i in seq_along(check_result$notes)) {
            todo_count <- todo_count + 1
            note_text <- trimws(check_result$notes[i])
            lines <- strsplit(note_text, "\\n")[[1]]
            main_note <- lines[1]
            cat(todo_count, ". [NOTE] ", main_note, "\\n", sep = "")
            if (length(lines) > 1) {
              for (j in 2:min(4, length(lines))) {
                if (nchar(trimws(lines[j])) > 0) {
                  cat("   ", trimws(lines[j]), "\\n", sep = "")
                }
              }
            }
            cat("\\n")
          }
        }

        if (todo_count == 0) {
          cat("✓ No issues found! Package passes R CMD check.\\n")
        } else {
          cat("\\nTotal issues to address: ", todo_count, "\\n", sep = "")
          cat("\\nFix errors first, then warnings, then consider addressing notes.\\n")
        }

        # Timing info
        duration <- check_result$duration
        if (!is.null(duration)) {
          cat("\\nCheck completed in ", format(duration), "\\n", sep = "")
        }
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_PKG_PATH: resolvedPath,
        R_CHECK_ARGS_JSON: JSON.stringify(parsedArgs),
        R_QUIET: quiet.toString()
      };

      // Execute R script asynchronously - allow more time for package checks
      const { stdout, stderr } = await execFileAsync('Rscript', ['-e', checkScript], {
        encoding: 'utf8',
        maxBuffer: 100 * 1024 * 1024, // 100MB buffer for check output
        timeout: 600000, // 10 minute timeout for package checks
        env: env
      });

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;

      // Check if it's a timeout
      if (error.code === 'ETIMEDOUT') {
        return {
          content: [
            {
              type: 'text',
              text: 'Error: Package check timed out after 10 minutes. The package might be too large or have hanging tests.',
            },
          ],
          isError: true,
        };
      }

      return {
        content: [
          {
            type: 'text',
            text: `Error running package check: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async run() {
    const transport = new StdioServerTransport();
    await this.server.connect(transport);
    console.error('R Help MCP server running on stdio');
  }
}

