  async getExamples({ function_name, package: pkg, run_examples = false }) {
    try {
      // Handle package::function syntax
      let actualFunction = function_name;
      let actualPackage = pkg;

      if (function_name.includes(':::') || function_name.includes('::')) {
        const parts = function_name.split(/:::?/);
        actualPackage = parts[0];
        actualFunction = parts[1];
      }

      // Remove backticks if present
      actualFunction = actualFunction.replace(/^`|`$/g, '');
      if (actualPackage) {
        actualPackage = actualPackage.replace(/^`|`$/g, '');
      }

      const examplesScript = `
        tryCatch({
          func_name <- Sys.getenv("R_FUNC_NAME")
          pkg_name <- Sys.getenv("R_PKG_NAME")
          run_examples <- Sys.getenv("R_RUN_EXAMPLES") == "true"

          # Get help file path
          help_path <- if (pkg_name != "") {
            tryCatch(
              help(topic = func_name, package = pkg_name),
              error = function(e) character(0)
            )
          } else {
            tryCatch(
              help(topic = func_name),
              error = function(e) character(0)
            )
          }

          if (length(help_path) == 0) {
            stop(paste0("No help found for function '", func_name, "'", 
                       if(pkg_name != "") paste0(" in package '", pkg_name, "'") else ""))
          }

          # Get the Rd file content
          rd_content <- utils:::.getHelpFile(help_path)

          # Extract examples section
          examples <- utils:::.Rd_get_metadata(rd_content, "examples")

          if (length(examples) == 0 || all(trimws(examples) == "")) {
            cat("No examples found for this function.\\n")
          } else {
            examples_text <- paste(examples, collapse = "\\n")

            if (run_examples) {
              cat("=== EXAMPLES CODE ===\\n")
              cat(examples_text)
              cat("\\n\\n=== RUNNING EXAMPLES ===\\n")

              # Create temporary file for examples
              temp_file <- tempfile(fileext = ".R")
              writeLines(examples_text, temp_file)

              # Run examples in a try-catch
              tryCatch({
                # Set up example environment
                example_env <- new.env(parent = globalenv())

                # Source the examples
                source(temp_file, local = example_env, echo = TRUE, 
                       print.eval = TRUE, verbose = FALSE)
              }, error = function(e) {
                cat("\\nError running examples: ", e$message, "\\n")
              }, warning = function(w) {
                cat("\\nWarning: ", w$message, "\\n")
              }, finally = {
                unlink(temp_file)
              })
            } else {
              cat("=== EXAMPLES CODE ===\\n")
              cat(examples_text)
              cat("\\n\\nNote: Use run_examples=true to execute these examples\\n")
            }
          }
        }, error = function(e) {
          cat(e$message, file = stderr())
          quit(save = "no", status = 1)
        })
      `;

      // Use environment variables to pass user input safely
      const env = {
        ...process.env,
        R_FUNC_NAME: actualFunction,
        R_PKG_NAME: actualPackage || '',
        R_RUN_EXAMPLES: run_examples.toString()
      };

      // Execute R script asynchronously with timeout (50MB for example output)
      const { stdout, stderr } = await execRScriptWithTimeout(examplesScript, env, 30000, 50);

      return {
        content: [
          {
            type: 'text',
            text: stdout.trim(),
          },
        ],
      };
    } catch (error) {
      const errorMessage = error.stderr ? error.stderr.trim() : error.message;
      return {
        content: [
          {
            type: 'text',
            text: `Error getting examples: ${errorMessage}`,
          },
        ],
        isError: true,
      };
    }
  }

  async getPackageInfo({ package: pkg, show_dependencies = true }) {
    try {
      const infoScript = `
        tryCatch({
          pkg_name <- Sys.getenv("R_PKG_NAME")
          show_deps <- Sys.getenv("R_SHOW_DEPS") == "true"

          # Check if package is installed
          if (!requireNamespace(pkg_name, quietly = TRUE)) {
            stop(paste0("Package '", pkg_name, "' is not installed"))
          }

          # Get package description
          desc <- packageDescription(pkg_name)

          # Basic info
          cat("=== PACKAGE INFORMATION ===\\n\\n")
          cat("Package: ", desc$Package, "\\n", sep = "")
          cat("Version: ", desc$Version, "\\n", sep = "")
          if (!is.null(desc$Title)) {
            cat("Title: ", desc$Title, "\\n", sep = "")
          }
          if (!is.null(desc$Description)) {
            cat("\\nDescription:\\n")
            # Wrap description text
            desc_text <- gsub("\\\\s+", " ", desc$Description)
            desc_text <- strwrap(desc_text, width = 70)
            cat(paste(desc_text, collapse = "\\n"), "\\n")
          }

          if (!is.null(desc$Author)) {
            cat("\\nAuthor: ", desc$Author, "\\n", sep = "")
          }
          if (!is.null(desc$Maintainer)) {
            cat("Maintainer: ", desc$Maintainer, "\\n", sep = "")
          }
          if (!is.null(desc$License)) {
            cat("License: ", desc$License, "\\n", sep = "")
          }
          if (!is.null(desc$URL)) {
            cat("URL: ", desc$URL, "\\n", sep = "")
          }
          if (!is.null(desc$BugReports)) {
            cat("Bug Reports: ", desc$BugReports, "\\n", sep = "")
          }

          # Get package path
          pkg_path <- find.package(pkg_name, quiet = TRUE)
          if (length(pkg_path) > 0) {
            cat("\\nInstalled at: ", pkg_path[1], "\\n", sep = "")
          }

          # Built information
          if (!is.null(desc$Built)) {
            cat("Built: ", desc$Built, "\\n", sep = "")
          }

          if (show_deps) {
            cat("\\n=== DEPENDENCIES ===\\n")

            # Depends
            if (!is.null(desc$Depends) && desc$Depends != "") {
              cat("\\nDepends:\\n")
              deps <- trimws(strsplit(desc$Depends, ",")[[1]])
              for (d in deps) {
                cat("  ", d, "\\n", sep = "")
              }
            }

            # Imports
            if (!is.null(desc$Imports) && desc$Imports != "") {
              cat("\\nImports:\\n")
              imports <- trimws(strsplit(desc$Imports, ",")[[1]])
              for (i in imports) {
                cat("  ", i, "\\n", sep = "")
              }
            }

            # Suggests
            if (!is.null(desc$Suggests) && desc$Suggests != "") {
              cat("\\nSuggests:\\n")
              suggests <- trimws(strsplit(desc$Suggests, ",")[[1]])
              for (s in suggests) {
                cat("  ", s, "\\n", sep = "")
              }
            }

            # LinkingTo
            if (!is.null(desc$LinkingTo) && desc$LinkingTo != "") {
              cat("\\nLinkingTo:\\n")
              linking <- trimws(strsplit(desc$LinkingTo, ",")[[1]])
              for (l in linking) {
                cat("  ", l, "\\n", sep = "")
              }
            }
          }

          # Check for datasets
          data_list <- tryCatch({
            data(package = pkg_name)$results[, "Item"]
          }, error = function(e) NULL)

          if (!is.null(data_list) && length(data_list) > 0) {
            cat("\\n=== DATASETS ===\\n")
            cat("Available datasets: ", length(data_list), "\\n", sep = "")
            for (d in data_list) {
