  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 2000);

    const { stdout } = await execFileAsync('Rscript', ['-e', 'Sys.sleep(10); cat("This should not print\\n")'], {
      signal: controller.signal
    });
    clearTimeout(timeout);
    console.log('✗ Should have timed out but completed:', stdout.trim());
  } catch (error) {
    if (error.name === 'AbortError') {
      console.log('✓ Success: Script timed out as expected');
    } else {
      console.log('✗ Failed with unexpected error:', error.message);
    }
  }

  // Test 3: Simulate help.search with timeout
  console.log('\nTest 3: Simulating help.search with timeout (3 seconds)');
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 3000);

    const searchScript = `
      # Simulate a potentially slow search
      tryCatch({
        results <- help.search("kernel", package="neuroim2")
        if (length(results$matches) > 0) {
          cat("Found", length(results$matches), "matches\\n")
        } else {
          cat("No matches found\\n")
        }
      }, error = function(e) {
        cat("Error:", e$message, "\\n")
      })
    `;

    const { stdout } = await execFileAsync('Rscript', ['-e', searchScript], {
      signal: controller.signal,
      encoding: 'utf8'
    });
    clearTimeout(timeout);
    console.log('✓ Completed within timeout:', stdout.trim());
  } catch (error) {
    if (error.name === 'AbortError') {
      console.log('✓ Timed out (this is OK - prevents hanging)');
    } else {
      console.log('✗ Failed with error:', error.message);
    }
  }
}

testTimeout().catch(console.error);

