#!/usr/bin/env node

// Simple test to verify help.search doesn't hang
import { execFile } from 'child_process';
import { promisify } from 'util';

const execFileAsync = promisify(execFile);

async function testSearch() {
  console.log('Testing help.search with pager disabled...\n');

  const testScript = `
    # Disable pager
    options(pager = "cat")

    # Test search in specific package
    cat("Test 1: Searching for 'kernel' in neuroim2\\n")
    results <- help.search("kernel", package = "neuroim2", rebuild = FALSE)

    if (!is.null(results$matches) && nrow(results$matches) > 0) {
      cat("Found", nrow(results$matches), "matches\\n")
      # Don't print the results object itself!
      matches <- results$matches
      for(i in 1:min(3, nrow(matches))) {
        cat("  -", matches[i, "Name"], "in", matches[i, "Package"], "\\n")
      }
    } else {
      cat("No matches found\\n")
    }

    # Test general search
    cat("\\nTest 2: General search for 'mean'\\n")
    results2 <- help.search("mean", rebuild = FALSE)
    if (!is.null(results2$matches) && nrow(results2$matches) > 0) {
      cat("Found", nrow(results2$matches), "matches\\n")
    } else {
      cat("No matches found\\n")
    }
  `;

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);

    const { stdout, stderr } = await execFileAsync('Rscript', ['-e', testScript], {
      signal: controller.signal,
      encoding: 'utf8'
    });

    clearTimeout(timeout);
    console.log('Output:\n', stdout);
    if (stderr) console.log('Stderr:\n', stderr);
    console.log('\n✓ Search completed without hanging!');
  } catch (error) {
    if (error.name === 'AbortError') {
      console.log('✗ Search timed out - pager issue may still exist');
    } else {
      console.log('✗ Error:', error.message);
    }
  }
}

testSearch().catch(console.error);

